182	function SuitesBody({
183	  state,
184	  connections,
185	  selectedId,
186	  onSelect,
187	  onEdit,
188	  onDeleted,
189	}: {
190	  state: AsyncState<Suite[]>;
191	  connections: Connection[];
192	  selectedId: string | null;
193	  onSelect: (id: string) => void;
194	  onEdit: (suite: Suite) => void;
195	  onDeleted: () => void;
196	}) {
197	  if (state.status === 'loading') {
198	    return <Spin tip="Loading suites…" size="large" style={{ marginTop: 80 }} />;
199	  }
200	  if (state.status === 'error') {
201	    return (
202	      <Alert
203	        type="error"
204	        showIcon
205	        title="Failed to load suites"
206	        description={state.error}
207	        style={{ margin: 24 }}
208	      />
209	    );
210	  }
211	  const suites = state.data;
212	  if (suites.length === 0) {
213	    return <Empty description="No suites yet — create one to start authoring checks." />;
