297	function SuiteDetail({
298	  suite,
299	  connections,
300	  onEdit,
301	  onDeleted,
302	}: {
303	  suite: Suite;
304	  connections: Connection[];
305	  onEdit: () => void;
306	  onDeleted: () => void;
307	}) {
308	  const { message, modal } = App.useApp();
309	  const navigate = useNavigate();
310	  // Remounted (keyed by suite.id) when the selection changes → checks refetch.
311	  const { state, reload } = useAsyncData(() => listChecks(suite.id));
312	  const connection = connections.find((c) => c.id === suite.connection_id);
313	  // The edit drawer (create is the dedicated /checks/new page) → open iff editing.
314	  const [editingCheck, setEditingCheck] = useState<Check | null>(null);
315	
316	  const [exporting, setExporting] = useState(false);
317	  const [shareOpen, setShareOpen] = useState(false);
318	  const [running, setRunning] = useState(false);
319	  // The live-progress drawer opens on the run id returned by a manual trigger.
320	  const [progressRunId, setProgressRunId] = useState<string | null>(null);
321	  // Managing shares (and deleting) needs admin; the read stamps the caller's level.
322	  const canManage = suite.my_permission === 'owner' || suite.my_permission === 'admin';
323	  // Triggering a run is edit-gated (matches the backend); a null target isn't runnable.
324	  const canRun = canManage || suite.my_permission === 'edit';
325	
326	  // Ref guard (not just `running` state) so a synchronous double-click can't
327	  // dispatch two runs in the render-tick before `loading` disables the button.
328	  const runningRef = useRef(false);
329	  const onRun = async () => {
330	    if (runningRef.current) return;
331	    runningRef.current = true;
332	    setRunning(true);
333	    try {
334	      const run = await runSuite(suite.id);
335	      message.success(`${suite.name}: run queued`);
336	      // Open the live-progress drawer on the queued run rather than bouncing to
337	      // /results — the user watches it execute check-by-check (and can cancel).
338	      setProgressRunId(run.id);
339	    } catch (err) {
340	      message.error(`Run failed: ${err instanceof Error ? err.message : 'unknown error'}`);
341	    } finally {
342	      runningRef.current = false;
343	      setRunning(false);
344	    }
345	  };
346	
347	  const onExport = async () => {
348	    setExporting(true);
349	    try {
350	      const doc = await exportSuite(suite.id);
351	      downloadJson(`${toFilenameStem(suite.name)}.json`, doc);
352	    } catch (err) {
353	      message.error(`Export failed: ${err instanceof Error ? err.message : 'unknown error'}`);
354	    } finally {
355	      setExporting(false);
356	    }
357	  };
358	
359	  const onDelete = () => {
360	    modal.confirm({
361	      title: `Delete “${suite.name}”?`,
362	      content: 'This removes the suite and all of its checks.',
363	      okText: 'Delete',
364	      okType: 'danger',
365	      onOk: async () => {
366	        try {
367	          await deleteSuite(suite.id);
368	          message.success(`${suite.name} deleted`);
369	          onDeleted();
370	        } catch (err) {
371	          message.error(`Delete failed: ${err instanceof Error ? err.message : 'unknown error'}`);
372	          throw err; // keep the confirm modal open on failure
373	        }
374	      },
375	    });
376	  };
377	
378	  return (
379	    <Flex vertical gap={16}>
380	      <Flex justify="space-between" align="flex-start" gap={12}>
381	        <Flex vertical gap={6}>
382	          <Typography.Title level={4} style={{ margin: 0 }}>
383	            {suite.name}
384	          </Typography.Title>
385	          {connection ? (
386	            <Flex gap={8} align="center">
387	              <Typography.Text type="secondary">
388	                {connection.name} · {CONNECTION_TYPE_LABELS[connection.type]}
389	              </Typography.Text>
390	              <Tag color={ENV_COLORS[connection.env]}>{envLabel(connection.env)}</Tag>
391	            </Flex>
392	          ) : (
393	            <Typography.Text type="secondary">Connection {suite.connection_id}</Typography.Text>
394	          )}
395	        </Flex>
396	        <Flex gap={8}>
397	          {canRun &&
398	            (suite.target ? (
399	              <Button
400	                type="primary"
401	                icon={<PlayCircleOutlined />}
402	                loading={running}
403	                onClick={onRun}
404	              >
405	                Run
406	              </Button>
407	            ) : (
408	              // No target yet → not runnable; show why rather than a 422 on click.
409	              // The <span> is required: a disabled antd Button has pointer-events:
410	              // none, so the Tooltip must hover the wrapper, not the button.
411	              <Tooltip title="Set a run target (Edit) before running this suite">
412	                <span style={{ cursor: 'not-allowed' }}>
413	                  <Button type="primary" icon={<PlayCircleOutlined />} disabled>
414	                    Run
415	                  </Button>
416	                </span>
417	              </Tooltip>
418	            ))}
419	          <Button onClick={() => setShareOpen(true)}>Share</Button>
420	          <Button loading={exporting} onClick={onExport}>
421	            Export
422	          </Button>
423	          <Button onClick={onEdit}>Edit</Button>
424	          <Button danger onClick={onDelete}>
425	            Delete
426	          </Button>
427	        </Flex>
428	      </Flex>
429	      {suite.description && <Typography.Paragraph>{suite.description}</Typography.Paragraph>}
430	      <ChecksList
431	        suiteId={suite.id}
432	        state={state}
433	        onAdd={() => navigate(`/suites/${suite.id}/checks/new`)}
434	        onEdit={(check) => setEditingCheck(check)}
435	        onChanged={reload}
436	      />
437	      {/* Triggers + schedules are edit-gated (same as runs): a pipeline/DAG bound
438	          here runs the suite on its success; a schedule runs it on a cron cadence.
439	          canRun is exactly the edit-level capability. */}
440	      <TriggersPanel suiteId={suite.id} canManage={canRun} />
441	      <SchedulesPanel suiteId={suite.id} canManage={canRun} />
442	      <CheckDrawer
443	        open={editingCheck !== null}
444	        suiteId={suite.id}
445	        check={editingCheck ?? undefined}
446	        target={suite.target}
447	        connectionType={connection?.type}
448	        onClose={() => setEditingCheck(null)}
449	        onSaved={() => {
450	          setEditingCheck(null);
451	          reload();
452	        }}
453	      />
454	      <SharePanel
455	        open={shareOpen}
456	        suiteId={suite.id}
457	        ownerId={suite.created_by}
458	        canManage={canManage}
459	        onClose={() => setShareOpen(false)}
460	      />
461	      <LiveRunProgress
462	        runId={progressRunId}
463	        suiteName={suite.name}
464	        canManage={canRun}
465	        onClose={() => setProgressRunId(null)}
466	      />
467	    </Flex>
468	  );
469	}
470	
471	function ChecksList({
472	  suiteId,
473	  state,
474	  onAdd,
475	  onEdit,
476	  onChanged,
477	}: {
478	  suiteId: string;
479	  state: AsyncState<Check[]>;
480	  onAdd: () => void;
481	  onEdit: (check: Check) => void;
482	  onChanged: () => void;
483	}) {
484	  const { message, modal } = App.useApp();
485	
486	  const onDelete = (check: Check) => {
487	    modal.confirm({
488	      title: `Delete “${check.name}”?`,
489	      okText: 'Delete',
490	      okType: 'danger',
491	      onOk: async () => {
492	        try {
493	          await deleteCheck(suiteId, check.id);
494	          message.success(`${check.name} deleted`);
495	          onChanged();
496	        } catch (err) {
497	          message.error(`Delete failed: ${err instanceof Error ? err.message : 'unknown error'}`);
498	          throw err; // keep the confirm modal open on failure
499	        }
500	      },
501	    });
502	  };
503	
504	  if (state.status === 'loading') {
505	    return <Spin tip="Loading checks…" />;
506	  }
507	  if (state.status === 'error') {
508	    return <Alert type="error" showIcon title="Failed to load checks" description={state.error} />;
509	  }
510	  const checks = state.data;
511	  return (
512	    <Card
513	      size="small"
514	      title={`Checks (${checks.length})`}
515	      extra={
516	        <Button type="primary" size="small" onClick={onAdd}>
517	          Add check
518	        </Button>
519	      }
520	    >
521	      {checks.length === 0 ? (
522	        <Empty
523	          image={Empty.PRESENTED_IMAGE_SIMPLE}
524	          description="No checks yet — add one to start."
525	        />
526	      ) : (
527	        <List
528	          dataSource={checks}
529	          renderItem={(check) => (
530	            <List.Item
531	              actions={[
532	                <Button key="edit" type="link" size="small" onClick={() => onEdit(check)}>
533	                  Edit
534	                </Button>,
535	                <Button
536	                  key="delete"
537	                  type="link"
538	                  size="small"
539	                  danger
540	                  onClick={() => onDelete(check)}
541	                >
542	                  Delete
543	                </Button>,
544	              ]}
545	            >
546	              <Flex vertical gap={2}>
547	                <Typography.Text strong>{check.name}</Typography.Text>
548	                <Typography.Text type="secondary" style={{ fontSize: 12 }}>
549	                  {check.expectation_type}
550	                </Typography.Text>
551	              </Flex>
552	            </List.Item>
553	          )}
554	        />
555	      )}
556	    </Card>
557	  );
558	}
