1	import type { ConnectionType } from '../../api/connections';
2	import type { RunTarget } from '../../api/suites';
3	
4	/**
5	 * A suite's run target (#215) is datasource-shaped: SQL warehouses identify a
6	 * `table` (+ optional `schema`), Unity Catalog adds a required `catalog`, and
7	 * flat-file stores (ADLS / S3) identify a `path` (+ optional `file_format`).
8	 * `targetKind` collapses the six datasource types to the three input shapes the
9	 * editor renders; orchestration types never reach here (they can't back a suite).
10	 */
11	export type TargetKind = 'sql' | 'uc' | 'flatfile';
12	
13	export function targetKind(type: ConnectionType): TargetKind | null {
14	  switch (type) {
15	    case 'snowflake':
16	      return 'sql';
17	    case 'unity_catalog':
18	      return 'uc';
19	    case 'adls_gen2':
20	    case 's3':
21	      return 'flatfile';
22	    default:
23	      return null; // adf / airflow — not a datasource
24	  }
25	}
26	
27	/** The raw target inputs the drawer collects (all optional strings). */
28	export interface TargetFormValues {
29	  target_table?: string;
30	  target_schema?: string;
31	  target_catalog?: string;
32	  target_path?: string;
33	  target_format?: 'csv' | 'parquet';
34	}
35	
36	/** Narrow an untyped stored `file_format` to the supported set, else `undefined`
37	 *  — the suite target is an untyped JSONB bag, so a stray value (e.g. `json`)
38	 *  must not prefill the Select with an option that doesn't exist. */
39	export function asFileFormat(value: string | undefined): 'csv' | 'parquet' | undefined {
40	  return value === 'csv' || value === 'parquet' ? value : undefined;
41	}
42	
43	export interface AssembledTarget {
44	  /** The target to send: `null` = leave targetless (no field was filled). */
45	  target: RunTarget | null;
46	  /** Set when the section was started but a required field is missing. */
47	  error?: { field: keyof TargetFormValues; message: string };
48	}
49	
50	const trimmed = (v?: string): string | undefined => {
51	  const t = v?.trim();
52	  return t ? t : undefined;
53	};
54	
55	/**
56	 * Turn the raw inputs into a `RunTarget` for the connection's datasource, mirroring
57	 * the backend `run_target.resolve_target` rules so a saved target is always
58	 * runnable. All-blank → `null` (a valid targetless suite). Partially filled but
59	 * missing the datasource's required field → an `error` naming that field, so the
60	 * UI flags it inline rather than letting the backend 422 on save.
61	 */
62	export function assembleTarget(kind: TargetKind, v: TargetFormValues): AssembledTarget {
63	  if (kind === 'flatfile') {
64	    const path = trimmed(v.target_path);
65	    if (!path && !v.target_format) return { target: null };
66	    if (!path) {
67	      return {
68	        target: null,
69	        error: { field: 'target_path', message: 'Path is required to run this suite.' },
70	      };
71	    }
72	    return { target: { path, ...(v.target_format ? { file_format: v.target_format } : {}) } };
73	  }
74	
75	  if (kind === 'sql') {
76	    const table = trimmed(v.target_table);
77	    const schema = trimmed(v.target_schema);
78	    if (!table && !schema) return { target: null };
79	    if (!table) {
80	      return {
81	        target: null,
82	        error: { field: 'target_table', message: 'Table is required to run this suite.' },
83	      };
84	    }
85	    return { target: { table, ...(schema ? { schema } : {}) } };
86	  }
87	
88	  // Unity Catalog: catalog + table required, schema optional.
89	  const catalog = trimmed(v.target_catalog);
90	  const table = trimmed(v.target_table);
91	  const schema = trimmed(v.target_schema);
92	  if (!catalog && !table && !schema) return { target: null };
93	  if (!catalog) {
94	    return {
95	      target: null,
96	      error: { field: 'target_catalog', message: 'Catalog is required to run this suite.' },
97	    };
98	  }
99	  if (!table) {
